  ('aboriginal-6f0ba476-moex-00230', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '下列何者不屬於會計上的現金？', '["即期支票", "勞退基金", "即期商業本票", "即期銀行匯票"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00231', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '下列敘述何者正確？', '["甲公司銷貨毛利率大於乙公司，則甲公司淨利率必大於乙公司", "甲公司流動比率大於乙公司，則甲公司速動比率（quickratio）必大於乙公司", "若兩家公司每股盈餘（EPS）相同，則價格盈餘比（P-Eratio）也一定會相同", "存貨週轉率越大的公司，其存貨週轉天數（Daysininventory）越小"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00232', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '有關銀行存款調節表的編製，下列敘述何者正確？', '["在途存款應列為公司帳列存款餘額的加項", "未兌現支票應列為公司帳列存款餘額的減項", "客戶存款不足退票應列為公司帳列存款餘額的減項", "銀行手續費應列為銀行對帳單餘額的加項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00233', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司X3年期初應收帳款$880,000，備抵損失$22,000，當年度銷貨總金額為$1,200,000（80%為 賒銷），應收帳款收現$780,000，應收帳款沖銷$9,000，請問在與前一年相同的預估損失率下，X3 年應提列的減損損失金額為多少？', '["$9,000", "$13,275", "$22,000", "$26,275"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00234', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於2022年1月1日購買土地，購價為$900,000,000，並另支付$1,550,000將土地上的舊建 築物拆除重建，殘料售得$105,000。此外，並支付建築師設計費$4,800,000，整地費$1,500,000，道 路鋪設費$1,950,000，土地過戶費$750,000，廠房建造工程費$800,550,000。試問土地成本為何？', '["$910,655,000", "$910,550,000", "$905,645,000", "$903,695,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00235', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '2022年1月1日甲公司共支付$1,936,467購買A公司於當日發行面值$1,800,000，票面利率12%， 將於2027年1月1日到期之債券，付息日為每年的12月31日，該債券投資按攤銷後成本衡量， 採用有效利率法攤銷折溢價。另已知該債券當日公允價值為$1,929,315，交易成本為$7,152。假設 在不考慮減損損失的情況下，試問下列何項敘述錯誤？', '["甲公司債券購買日的分錄應借記：按攤銷後成本衡量之債券投資$1,929,315及手續費$7,152，貸 記：現金$1,936,467", "該債券投資帳面金額會逐年減少", "該債券有效利率小於12%", "甲公司於2022年 12月31日認列的利息收入低於$216,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00236', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '下列有關生物資產與農產品會計處理，何者錯誤？', '["原則上生物資產應以淨公允價值（公允價值減去出售成本）衡量", "計算生物資產淨公允價值時，出售成本不包含將生物資產運送至市場之運輸成本", "若生物資產之公允價值無法可靠衡量時，應採用成本模式", "農產品收成時應以淨公允價值模式衡量，但也可採用成本模式"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00237', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '下列有關無形資產會計處理，何者錯誤？', '["無形資產研究階段時的相關支出，發生時應認列為當期費用", "無形資產的支出若無法區分是研究階段或發展階段，則僅能將相關支出視為研究階段之支出", "非確定耐用年限的無形資產，無論有無減損跡象，每年都需進行減損測試", "公司為維護專利權而發生之訴訟費用，若勝訴則相關訴訟費用列為專利權的成本，若敗訴則列 為期間費用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00238', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司在2022年1月1日支付$100,000,000購入一筆土地，代書費用$1,000,000，公司行政人員費用 $400,000，購置目的為以收取租金收益為持有目的之投資性不動產，此項交易採用公允價值模式衡量。 2022年7月1日將土地出租給A公司，每年租金為$8,000,000，2022年12月31日土地公允價值為 $108,000,000。試問甲公司2022年相關財務報表有關上述投資不動產之表達何者正確？', '["購入投資性不動產-土地成本為$101,400,000", "2022年度租金收入$8,000,000", "2022年12月31日資產負債表中不動產、廠房及設備-土地表達金額為$100,000,000", "2022年12月31日損益表中公允價值調整利益-投資性不動產土地為$7,000,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00239', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於2020年1月1日發行5年期總面額$700,000、票面利率為8%之公司債購買土地，依據 合約公司每年12月31日須支付利息$56,000。假定發行該公司債無交易成本，公司採用攤銷後成 本法，並以有效利率法攤銷債券折溢價。已知甲公司該公司債於2020年12月31日及2021年12 月31日帳面價值（帳面金額）分別為$655,622及$665,184。試問有關此公司債的有效利率為何？ （利息費用的計算採四捨五入至元）', '["6%", "8%", "10%", "12%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
